'use client';

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    X, ChevronDown, ChevronUp, Loader2, Check,
} from 'lucide-react';
import { useFilters } from '@/hooks/useFilters';
import type { ActiveFilter } from './FilterChips';

/* ─── Types ──────────────────────────────────────────────────────────── */
export interface FilterOption {
    value: string;
    label: string;
    count?: number;
}

export interface FilterGroup {
    key: string;
    title: string;
    type: 'checkbox' | 'color' | 'pill' | 'price' | 'rating';
    options: FilterOption[];
    colors?: { name: string; hex: string; value: string }[];
}

interface SortOption {
    value: string;
    label: string;
}

interface MobileFilterSheetProps {
    isOpen: boolean;
    onClose: () => void;
    filterGroups: FilterGroup[];
    sortOptions: SortOption[];
    activeFilters: ActiveFilter[];
    activeSortValue: string;
    resultCount: number;
    isLoading?: boolean;
    onFilterChange: (key: string, value: string, checked: boolean) => void;
    onSortChange: (value: string) => void;
    onClearAll: () => void;
}

// Forced re-compile: 2026-03-07T18:21:45
/* ─── Main sheet ─────────────────────────────────────────────────────── */
export default function MobileFilterSheet({
    isOpen,
    onClose,
    filterGroups,
    sortOptions,
    activeFilters,
    activeSortValue,
    resultCount,
    isLoading = false,
    onFilterChange,
    onSortChange,
    onClearAll,
}: MobileFilterSheetProps) {
    // 1. All Hooks at the very top
    const [mounted, setMounted] = useState(false);
    const [activeTab, setActiveTab] = useState<'filter' | 'sort'>('filter');
    const [openAccordions, setOpenAccordions] = useState<Record<string, boolean>>({});

    const dragStartY = useRef(0);
    const sheetRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);

    const { filters, setPriceRange } = useFilters();

    useEffect(() => {
        setMounted(true);
    }, []);

    const toggleAccordion = useCallback((key: string) => {
        setOpenAccordions(prev => ({ ...prev, [key]: !prev[key] }));
    }, []);

    const onDragStart = useCallback((e: React.TouchEvent) => {
        dragStartY.current = e.touches[0].clientY;
        isDragging.current = true;
        if (sheetRef.current) {
            sheetRef.current.style.transition = 'none';
        }
    }, []);

    const onDragMove = useCallback((e: React.TouchEvent) => {
        if (!isDragging.current || !sheetRef.current) return;
        const delta = Math.max(0, e.touches[0].clientY - dragStartY.current);
        sheetRef.current.style.transform = `translateY(${delta}px)`;
    }, []);

    const onDragEnd = useCallback((e: React.TouchEvent) => {
        isDragging.current = false;
        const delta = e.changedTouches[0].clientY - dragStartY.current;
        if (!sheetRef.current) return;
        sheetRef.current.style.transition = '';
        if (delta > 150) {
            onClose();
        } else {
            sheetRef.current.style.transform = '';
        }
    }, [onClose]);

    // 2. Early return AFTER hooks
    if (!mounted) return null;

    return (
        <AnimatePresence>
            {/* Backdrop */}
            {isOpen && (
                <motion.div
                    key="backdrop"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 z-[48] bg-black/60 backdrop-blur-[2px]"
                />
            )}

            {/* Sheet */}
            {isOpen && (
                <motion.div
                    key="sheet"
                    ref={sheetRef}
                    initial={{ y: '100%' }}
                    animate={{ y: 0 }}
                    exit={{ y: '100%' }}
                    transition={{ type: 'spring', damping: 32, stiffness: 300, mass: 0.8 }}
                    className="fixed bottom-0 left-0 right-0 z-[49] bg-white dark:bg-[#1C1C1E] flex flex-col overflow-hidden"
                    style={{
                        height: '94vh',
                        borderRadius: '24px 24px 0 0',
                        paddingBottom: 'env(safe-area-inset-bottom)',
                    }}
                >
                    {/* Drag handle */}
                    <div
                        className="flex-shrink-0 pt-3 pb-2 flex justify-center cursor-grab active:cursor-grabbing"
                        onTouchStart={onDragStart}
                        onTouchMove={onDragMove}
                        onTouchEnd={onDragEnd}
                    >
                        <div className="w-12 h-1.5 rounded-full bg-[#E8E3DC]" />
                    </div>

                    {/* Header */}
                    <div className="flex-shrink-0 flex items-center justify-between px-6 pb-4 pt-2">
                        <div className="flex flex-col">
                            <h2 className="text-2xl font-serif text-[#1C1C1E] tracking-tight lowercase">Filtreleme</h2>
                            <p className="text-[11px] font-sans font-bold uppercase tracking-[0.2em] text-[#999] mt-0.5">Ve Sıralama Seçenekleri</p>
                        </div>
                        <div className="flex items-center gap-4">
                            {activeFilters.length > 0 && (
                                <button onClick={onClearAll} className="text-[12px] font-bold text-[#C9A96E] uppercase tracking-wider">
                                    Sıfırla
                                </button>
                            )}
                            <button
                                onClick={onClose}
                                className="w-10 h-10 flex items-center justify-center rounded-full bg-[#F5F0EB] transition-transform active:scale-90 text-[#1C1C1E]"
                                aria-label="Kapat"
                            >
                                <X size={18} />
                            </button>
                        </div>
                    </div>

                    {/* Tabs */}
                    <div className="flex-shrink-0 flex px-6 mb-4">
                        {(['filter', 'sort'] as const).map(tab => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className="flex-1 py-4 text-[13px] font-bold uppercase tracking-[0.2em] relative"
                                style={{
                                    color: activeTab === tab ? '#1C1C1E' : '#BBB',
                                    WebkitTapHighlightColor: 'transparent',
                                }}
                            >
                                {tab === 'filter' ? 'Filtreler' : 'Sıralama'}
                                {activeTab === tab && (
                                    <motion.div
                                        layoutId="filterSheetTabLuxury"
                                        transition={{ type: 'spring', damping: 20, stiffness: 200 }}
                                        className="absolute bottom-0 left-0 right-0 h-1 bg-[#1C1C1E] rounded-full"
                                    />
                                )}
                            </button>
                        ))}
                    </div>

                    {/* Scrollable content */}
                    <div className="flex-1 overflow-y-auto px-6" style={{ WebkitOverflowScrolling: 'touch' }}>
                        {activeTab === 'filter' ? (
                            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
                                {filterGroups.map(group => {
                                    const isOpenAccordion = openAccordions[group.key] || false;
                                    const selectedCount = activeFilters.filter(f => f.key === group.key).length;

                                    return (
                                        <div key={group.key} className="border-b border-[#F5F0EB]">
                                            <button
                                                className="flex items-center justify-between w-full py-5 text-left"
                                                style={{ WebkitTapHighlightColor: 'transparent' }}
                                                onClick={() => toggleAccordion(group.key)}
                                                aria-expanded={isOpenAccordion}
                                            >
                                                <span className="text-[14px] font-bold uppercase tracking-widest text-[#1C1C1E] flex items-center gap-3">
                                                    {group.title}
                                                    {selectedCount > 0 && (
                                                        <span className="w-5 h-5 rounded-full bg-[#C9A96E] text-white text-[10px] font-bold flex items-center justify-center">
                                                            {selectedCount}
                                                        </span>
                                                    )}
                                                </span>
                                                <motion.div animate={{ rotate: isOpenAccordion ? 180 : 0 }} transition={{ duration: 0.3, ease: [0.22, 1, 0.36, 1] }}>
                                                    <ChevronDown size={18} className="text-[#999]" />
                                                </motion.div>
                                            </button>

                                            <AnimatePresence initial={false}>
                                                {isOpenAccordion && (
                                                    <motion.div
                                                        initial={{ height: 0, opacity: 0 }}
                                                        animate={{ height: 'auto', opacity: 1 }}
                                                        exit={{ height: 0, opacity: 0 }}
                                                        transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
                                                    >
                                                        <div className="overflow-hidden pb-5">
                                                            {/* Checkbox list */}
                                                            {(group.type === 'checkbox' || group.type === 'rating') && (
                                                                <div className="flex flex-col gap-1">
                                                                    {group.options.map(opt => {
                                                                        const checked = activeFilters.some(f => f.key === group.key && f.value === opt.value);
                                                                        return (
                                                                            <label key={opt.value} className="flex items-center gap-4 py-3 cursor-pointer group" style={{ minHeight: 48, WebkitTapHighlightColor: 'transparent' }}>
                                                                                <div className="w-5 h-5 rounded-none flex-shrink-0 flex items-center justify-center border transition-all duration-300" style={{ borderColor: checked ? '#1C1C1E' : '#E8E3DC', background: checked ? '#1C1C1E' : 'white' }}>
                                                                                    {checked && <Check size={12} className="text-white" />}
                                                                                </div>
                                                                                <input type="checkbox" className="sr-only" checked={checked} onChange={e => onFilterChange(group.key, opt.value, e.target.checked)} />
                                                                                <span className={`text-[15px] transition-colors ${checked ? 'text-[#1C1C1E] font-medium' : 'text-[#666]'}`}>{opt.label}</span>
                                                                                {opt.count !== undefined && <span className="text-[12px] text-[#bbb] ml-auto">({opt.count})</span>}
                                                                            </label>
                                                                        );
                                                                    })}
                                                                </div>
                                                            )}
                                                            {/* Color swatches */}
                                                            {group.type === 'color' && group.colors && (
                                                                <div className="grid grid-cols-5 gap-4 pt-2">
                                                                    {group.colors.map(c => {
                                                                        const checked = activeFilters.some(f => f.key === group.key && f.value === c.value);
                                                                        return (
                                                                            <button key={c.value} onClick={() => onFilterChange(group.key, c.value, !checked)} className="flex flex-col items-center gap-2" style={{ WebkitTapHighlightColor: 'transparent' }} aria-label={c.name} aria-pressed={checked}>
                                                                                <div className="w-12 h-12 rounded-full relative flex items-center justify-center transition-all duration-500" style={{ background: c.hex, boxShadow: checked ? '0 0 0 1px #1C1C1E, 0 0 0 4px white, 0 8px 16px rgba(0,0,0,0.1)' : '0 2px 8px rgba(0,0,0,0.05)', transform: checked ? 'scale(1.05)' : 'scale(1)' }}>
                                                                                    {checked && <div className={`w-1.5 h-1.5 rounded-full ${c.hex === '#FAFAFA' || c.hex === '#D4C5B2' ? 'bg-[#1C1C1E]' : 'bg-white'}`} />}
                                                                                </div>
                                                                                <span className="text-[10px] font-bold uppercase tracking-wider text-[#999] text-center leading-tight">{c.name}</span>
                                                                            </button>
                                                                        );
                                                                    })}
                                                                </div>
                                                            )}
                                                            {/* Price range */}
                                                            {group.type === 'price' && (
                                                                <div className="flex items-center gap-4 pt-2">
                                                                    <div className="flex-1 relative">
                                                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-[10px] font-bold text-[#999]">MIN</span>
                                                                        <input type="number" placeholder="₺" inputMode="numeric" value={filters.priceRange[0]} onChange={(e) => {
                                                                            const val = parseInt(e.target.value) || 0;
                                                                            setPriceRange([val, filters.priceRange[1]]);
                                                                        }} className="w-full border border-[#E8E3DC] rounded-none pl-12 pr-4 py-4 text-[14px] font-medium focus:border-[#1C1C1E] outline-none transition-colors" />
                                                                    </div>
                                                                    <div className="w-4 h-px bg-[#E8E3DC]" />
                                                                    <div className="flex-1 relative">
                                                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-[10px] font-bold text-[#999]">MAX</span>
                                                                        <input type="number" placeholder="₺" inputMode="numeric" value={filters.priceRange[1]} onChange={(e) => {
                                                                            const val = parseInt(e.target.value) || 0;
                                                                            setPriceRange([filters.priceRange[0], val]);
                                                                        }} className="w-full border border-[#E8E3DC] rounded-none pl-12 pr-4 py-4 text-[14px] font-medium focus:border-[#1C1C1E] outline-none transition-colors" />
                                                                    </div>
                                                                </div>
                                                            )}
                                                        </div>
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    );
                                })}
                            </div>
                        ) : (
                            <div className="py-4 flex flex-col gap-2 animate-in fade-in slide-in-from-bottom-2 duration-500">
                                {sortOptions.map(opt => (
                                    <label key={opt.value} className="flex items-center justify-between py-5 px-4 rounded-none border-b border-[#F5F0EB] cursor-pointer active:bg-[#F5F0EB] transition-colors" style={{ minHeight: 64, WebkitTapHighlightColor: 'transparent' }}>
                                        <span className={`text-[15px] ${activeSortValue === opt.value ? 'text-[#1C1C1E] font-bold' : 'text-[#666]'}`}>{opt.label}</span>
                                        <div className="w-6 h-6 rounded-full border flex items-center justify-center flex-shrink-0 transition-all duration-300" style={{ borderColor: activeSortValue === opt.value ? '#1C1C1E' : '#E8E3DC', background: activeSortValue === opt.value ? '#1C1C1E' : 'transparent' }}>
                                            {activeSortValue === opt.value && <Check size={14} className="text-white" />}
                                        </div>
                                        <input type="radio" className="sr-only" name="sort" value={opt.value} checked={activeSortValue === opt.value} onChange={() => onSortChange(opt.value)} />
                                    </label>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Bottom Action Area */}
                    <div className="flex-shrink-0 px-8 pt-6 pb-10 border-t border-[#F5F0EB] bg-white shadow-[0_-20px_40px_rgba(0,0,0,0.04)]">
                        <button
                            onClick={onClose}
                            disabled={isLoading}
                            className={`w-full py-5 rounded-none text-[13px] font-bold uppercase tracking-[0.3em] text-white flex items-center justify-center gap-3 transition-all duration-500 shadow-xl ${isLoading ? 'bg-[#999]' : 'bg-[#1C1C1E] hover:bg-[#333] active:scale-[0.98]'}`}
                            style={{ WebkitTapHighlightColor: 'transparent' }}
                        >
                            {isLoading ? (
                                <>
                                    <Loader2 size={16} className="animate-spin" />
                                    Yükleniyor
                                </>
                            ) : (
                                <>
                                    <span>Koleksiyonu Gör</span>
                                    <span className="opacity-40 text-[11px]">({resultCount})</span>
                                </>
                            )}
                        </button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}
